import{_ as i,I as n,c as l,o as p,ak as e,J as r,j as t,a as s,aN as d,aO as u}from"./chunks/framework.Bsrd6u7g.js";const A=JSON.parse('{"title":"ETS2LA C# 五月开发日志","description":"","frontmatter":{"slug":"devblog-may-2026","title":"ETS2LA C# 五月开发日志","authors":["tumppi066"],"translate":["晚安"],"tags":["news","C#"]},"headers":[],"relativePath":"updates/2026-5-27-may-cs-update.md","filePath":"updates/2026-5-27-may-cs-update.md"}'),m={name:"updates/2026-5-27-may-cs-update.md"};function h(g,a,c,_,T,C){const o=n("ImageCaption");return p(),l("div",null,[a[0]||(a[0]=e('<p>与过去几个月相比，我们的开发速度有了显著提升。你们中的一些人可能已经在 Discord 上看到了预览，这里我会详细介绍。</p><h3 id="发布计划" tabindex="-1">发布计划 <a class="header-anchor" href="#发布计划" aria-label="Permalink to “发布计划”">​</a></h3><p>目前我们只差一个主要功能（ACC）就可以发布公开测试版了。这意味着 <strong>我们将在下个月底之前推出 C# 首个公开测试版</strong>。这个初始测试版肯定会缺少一些功能，但相比 Python 版本也会有许多改进。在 C# 正式发布之前，我们将继续同时支持两个版本。</p><p>在正式发布之前，你们应该还能看到一期开发日志。开发日志将在发布后继续更新，我们将用它来汇总更新内容，如果社区有足够兴趣，我们可能会展示一些内部功能的实现原理。</p><h3 id="车道保持-导航功能的改进" tabindex="-1">车道保持/导航功能的改进 <a class="header-anchor" href="#车道保持-导航功能的改进" aria-label="Permalink to “车道保持/导航功能的改进”">​</a></h3><p>上个月我预告了车道保持系统的第一个版本。在那之后，系统有了很大的改进。虽然离一个 <em>优秀</em> 的系统还有距离，但以目前的状态来看，测试者的反馈很不错。下面是一段视频，展示当前系统在游戏中跟随导航路线行驶的效果。</p><video controls width="100%"><source src="'+u+'" type="video/mp4"> 您的浏览器不支持视频标签。 </video>',7)),r(o,{caption:"ETS2LA C# 在瑞典行驶中"}),a[1]||(a[1]=t("p",null,"与上个月的视频一样，这里的转向输出没有任何滤波处理。这意味着你们看到的是我们转向算法的原始输出，在正式发布时会被平滑处理。还有一些奇怪的车道选择问题、变道不够平滑，以及系统偶尔会无法确定下一个路径。不过总体来说，我认为我们已经达到了 Python 版本的水平，而且这次没有任何延迟峰值或奇怪的抖动！",-1)),a[2]||(a[2]=t("h3",{id:"功能性-ui",tabindex:"-1"},[s("功能性 UI "),t("a",{class:"header-anchor",href:"#功能性-ui","aria-label":"Permalink to “功能性 UI”"},"​")],-1)),a[3]||(a[3]=t("p",null,"在开发的最初阶段，大部分设置不会向用户开放。然而随着我们越来越接近发布，无需额外设置就能使用这些选项就变得很重要。我吸取了这些年开发 Python 版本的一些经验教训，目标是为用户提供更好的入门体验，同时实现一些期待已久的功能。",-1)),a[4]||(a[4]=t("p",null,"其中一个功能就是直接从界面更改 ETS2LA 的显示单位。由于多个结构性问题，这在 Python 版本中是不可能的，但在 C# 中实现起来却轻而易举。",-1)),a[5]||(a[5]=t("video",{controls:"",width:"100%"},[t("source",{src:d,type:"video/mp4"}),s(" 您的浏览器不支持视频标签。 ")],-1)),r(o,{caption:"动态更改显示单位"}),a[6]||(a[6]=e('<p>UI 工作将在公开测试版发布后继续。你们现在看到的很可能不是我们 UI 的最终版本，而且目前的底层代码也有些未完成。如果你有任何有趣的反馈或建议，可以告诉我们。我们始终对社区的想法感兴趣！个人而言，我开始喜欢 Rivian 在 UI 上的做法，也许我们会从中获得一些灵感 ;</p><h3 id="操作系统支持" tabindex="-1">操作系统支持 <a class="header-anchor" href="#操作系统支持" aria-label="Permalink to “操作系统支持”">​</a></h3><p>之前已经提到 ETS2LA 将在 Windows 和 Linux 上原生运行。然而由于 <strong>playzzero</strong> 的工作，我们现在也在添加 MacOS 支持。虽然我没有什么值得展示的视频（毕竟还在开发中），但我可以信心地说，我们将在公开测试版发布时或之后的版本中支持 MacOS。</p><p>不过需要注意的是，你不能混用不同版本。例如，如果你在 Proton 中运行游戏，你也必须在那同一个容器中运行 ETS2LA。本质上它们需要在同一个&quot;逻辑&quot;系统上运行，虚拟机不算作主操作系统的一部分。</p><h3 id="关于-ko-fi-的公告" tabindex="-1">关于 Ko-Fi 的公告 <a class="header-anchor" href="#关于-ko-fi-的公告" aria-label="Permalink to “关于 Ko-Fi 的公告”">​</a></h3><p>随着公开测试版的临近，我也会关闭现有的 Ko-Fi 赞助页面。将来人们将能够支持这个项目 <em>同时</em> 获得一些回报。我不喜欢在这种有偿情况下请求捐赠。作为对现有支持者的感谢，他们将获得与捐赠金额相等的外加一个月的订阅时间（即 3€ 捐赠 = 2 个月）。</p><p>这里需要重点说明的是，订阅对于服务器端功能完全是可选的。一个功能是否需要订阅很简单：它是否需要我花钱运行？如果是，那就是订阅功能。任何在你电脑上运行的东西对我来说零成本，因此 <strong>不会设置订阅门槛</strong>。</p><h3 id="下个月可以期待什么" tabindex="-1">下个月可以期待什么 <a class="header-anchor" href="#下个月可以期待什么" aria-label="Permalink to “下个月可以期待什么”">​</a></h3><p>我必须强调，下个月的发布顾名思义是一个 <strong>公开测试版</strong>。会有功能缺失和 bug，说实话这正是我们想要的。封闭测试版的测试者一直在做出色的工作，但我们仍然需要更多人测试 ETS2LA 在各种不同场景下的表现。我们将根据你们的反馈修复 bug 和添加功能，希望 ETS2LA C# 的测试期不会超过一两个月！</p><p>话虽如此，以下是你可以期待在下个月看到的内容：</p><ul><li><strong>UI 的初版</strong>，这可能会根据反馈重新制作。</li><li><strong>没有可视化或地图页面</strong>，ETS2LA C# 将只附带一个类似上方视频中的 AR HUD。可视化和地图页面将在未来重新制作，尤其是可视化需要较长时间。</li><li><strong>导航、车道保持和 ACC 将可用</strong>，但可能缺少一些功能并有 bug。这些功能在几周内会有显著改进。</li><li><strong>第三方插件支持</strong>，我们将提供与现在类似的插件目录。我们的官方插件也会在目录中。</li><li><strong>初更好的入门体验</strong>，这可能会比我们现在拥有的更好。</li><li>支持 <strong>Windows、Linux 和 MacOS</strong>。</li></ul><p>大部分缺失的功能将在发布后的几周内添加。这与我们仍在设计中的网络功能是分开的。这意味着订阅不会在发布时可用，而是会在将来添加。同样，你们现在拥有的功能不会被拿走，订阅将附带额外的服务器端功能来支持开发。</p><p>希望你们对 ETS2LA 的热情和我一样——这将是我们做过的最大改变，我迫不及待想和你们分享！</p><h2 id="感谢阅读" tabindex="-1"><strong>感谢阅读！</strong> <a class="header-anchor" href="#感谢阅读" aria-label="Permalink to “感谢阅读！”">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>如果你对代码感兴趣（也许你将来可以创建 C# 插件！），请查看<a href="/docs/Rewrite/Introduction.html">文档</a>中的代码示例和说明。这仍在开发中，但应该能让你对预期内容有很好的了解。 我们张开双臂欢迎所有 C# 开发者，我的经验主要限于 Unity，所以一路上也在学习如何用&quot;正确的方式&quot;做事情。请记住，我们不允许在代码库中使用 AI 智能体，我们重视个人的努力，而非 AI 表面上的&quot;效率&quot;。</p></div>',15))])}const S=i(m,[["render",h]]);export{A as __pageData,S as default};
